sql:
SELECT dataset_id, COUNT(*) AS number_of_versions
FROM dataset_versions
GROUP BY dataset_id;

SELECT version_name, created_date
FROM dataset_versions
WHERE dataset_id = 1;

SELECT datasets.dataset_name, evaluation_metrics.metric_name
FROM datasets
INNER JOIN evaluation_metrics ON datasets.dataset_id = evaluation_metrics.dataset_id;

SELECT datasets.dataset_name, ground_truth.ground_truth_name
FROM datasets
INNER JOIN ground_truth ON datasets.dataset_id = ground_truth.dataset_id;

SELECT metric_name, metric_value 
FROM evaluation_metrics 
WHERE dataset_id = 1 AND evaluation_metric_id = 2;

external_knowledge:
- "surpassed the mark of 5 megabytes in size" refers to datasets where size_in_bytes > 5000000;
- "currently flourishing" refers to datasets with active versions, where version_status = 'active';
- "revealing the average performance score" means calculating the average of metric_value for each combination of dataset_name, version_name, and ground_truth_name;
- The vibrant entities mentioned here refer to the datasets, versions, and ground-truth data.

sql:
SELECT dv.version_name, ev.metric_value AS max_metric_value
FROM dataset_versions dv
JOIN evaluation_metric_values ev ON dv.version_id = ev.version_id
WHERE ev.metric_value = (
    SELECT MAX(metric_value) FROM evaluation_metric_values
);
